"""Core operations over harvest records."""


def _validate_category(category):
    if not isinstance(category, str) or not category.strip():
        raise ValueError("category must be a non-empty string")


def _validate_bushels(bushels):
    try:
        bushels = float(bushels)
    except (TypeError, ValueError):
        raise ValueError("bushels must be a number") from None
    if bushels < 0:
        raise ValueError("bushels must not be negative")
    return bushels


def add_record(records, category, bushels, note=""):
    """Append a harvest record and return it."""
    _validate_category(category)
    bushels = _validate_bushels(bushels)
    record = {
        "category": category,
        "bushels": bushels,
        "note": note,
    }
    records.append(record)
    return record


def total_bushels(records):
    """Sum the bushels field across records."""
    return sum(r["bushels"] for r in records)


def filter_by_category(records, category):
    """Return records whose category matches (case-insensitive)."""
    _validate_category(category)
    return [r for r in records if r["category"] == category]


def top_categories(records, limit=3):
    """Return the ``limit`` categories with the highest summed bushels."""
    if not isinstance(limit, int) or isinstance(limit, bool) or limit < 1:
        raise ValueError("limit must be a positive integer")
    totals = {}
    for r in records:
        totals[r["category"]] = totals.get(r["category"], 0.0) + r["bushels"]
    ranked = sorted(totals.items(), key=lambda kv: (-kv[1], kv[0]))
    return ranked[:limit]


def category_report(records):
    """Return ``(category, count, total)`` tuples sorted by total, highest first."""
    stats = {}
    for r in records:
        count, total = stats.get(r["category"], (0, 0.0))
        stats[r["category"]] = (count + 1, total + r["bushels"])
    ranked = sorted(stats.items(), key=lambda kv: (-kv[1][1], kv[0]))
    return [(category, count, total) for category, (count, total) in ranked]

